import "./App.css";

function App() {
  return (
    <div className="App">
      <head>
        <script
          src="https://unpkg.com/react@18/umd/react.development.js"
          crossorigin
        ></script>
        <script
          src="https://unpkg.com/react-dom@18/umd/react-dom.development.js"
          crossorigin
        ></script>
        <script src="https://unpkg.com/@babel/standalone/babel.min.js"></script>
      </head>
      <header></header>
      <body>
        <h1 class="tomRad">Hello, I am Tomas Radic, front-End developer.</h1>
      </body>
    </div>
  );
}

export default App;
